What does the following program print?

```cpp
#include <iostream>
#include <optional>

int main() {
    std::optional<int> a = 5;
    std::optional<int> b;
    std::cout << a.value_or(99) << '\n';
    std::cout << b.value_or(99) << '\n';
}
```

What does the following program print?

```cpp
#include <iostream>
#include <optional>

std::optional<int> first_even(const int* arr, int n) {
    for (int i = 0; i < n; ++i)
        if (arr[i] % 2 == 0) return arr[i];
    return std::nullopt;
}

int main() {
    int a[] = {1, 3, 5};
    int b[] = {1, 4, 6};
    auto ra = first_even(a, 3);
    auto rb = first_even(b, 3);
    std::cout << ra.has_value() << '\n';
    std::cout << *rb << '\n';
}
```

The function below should return the square root candidate that, when squared, gives exactly `n`, or nothing if no such integer exists (1 ≤ n ≤ 10000). There is one bug — the wrong answer is returned for perfect squares.

```cpp
#include <optional>

std::optional<int> intSqrt(int n) {
    for (int i = 1; i * i <= n; ++i)
        if (i * i == n) return std::nullopt;  // bug
    return std::nullopt;
}
```
